import { useState } from "react";

const bookData = [
  {
    id: 1,
    title: "Clean Code",
    author: "Robert C Martin",
    genre: "Programming",
    available: true,
    cover: "https://covers.openlibrary.org/b/id/9611996-L.jpg"
  },
  {
    id: 2,
    title: "Harry Potter",
    author: "J K Rowling",
    genre: "Fantasy",
    available: false,
    cover: "https://covers.openlibrary.org/b/id/7984916-L.jpg"
  }
];

function Books() {
  const [search, setSearch] = useState("");

  const filteredBooks = bookData.filter(book =>
    book.title.toLowerCase().includes(search.toLowerCase()) ||
    book.author.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div>
      <h2>Library Books</h2>

      <input
        placeholder="Search by title or author"
        onChange={(e) => setSearch(e.target.value)}
      />

      <br /><br />

      {filteredBooks.map(book => (
        <div key={book.id} style={{ border: "1px solid gray", padding: "10px", margin: "10px" }}>
          <img src={book.cover} width="80" />
          <h3>{book.title}</h3>
          <p>{book.author}</p>
          <p>{book.genre}</p>
          <p>
            Status: {book.available ? "Available ✅" : "Not Available ❌"}
          </p>
        </div>
      ))}
    </div>
  );
}

export default Books;
